import React, { useState, useRef, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { Users, Clock, Trophy, Send, Palette, Eraser, RotateCcw, Undo, CheckCircle, XCircle } from 'lucide-react';
import { db } from '../../firebase';
import { ref, onValue, push, set, update, serverTimestamp, get } from 'firebase/database';
import styles from './Canvas.module.css';

// Word list for the game
const WORDS = [
  'BUTTERFLY', 'ELEPHANT', 'GUITAR', 'MOUNTAIN', 'RAINBOW', 'DIAMOND', 'OCTOPUS', 'PYRAMID', 'VOLCANO', 'WHALE',
  'ZEBRA', 'BALLOON', 'CAMERA', 'DRAGON', 'EAGLE', 'FROG', 'GHOST', 'HORSE', 'IGLOO', 'JELLYFISH',
  'KANGAROO', 'LION', 'MONKEY', 'NINJA', 'OWL', 'PENGUIN', 'QUEEN', 'ROBOT', 'SNAKE', 'TIGER',
  'UMBRELLA', 'VIOLIN', 'WOLF', 'XYLOPHONE', 'YACHT', 'ZOMBIE', 'APPLE', 'BANANA', 'CHERRY', 'DONUT'
];

const DrawingGame = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [gameState, setGameState] = useState('playing');
  const [gamePhase, setGamePhase] = useState('drawing'); // 'drawing' or 'guessing'
  const [currentDrawerIndex, setCurrentDrawerIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(30);
  const [round, setRound] = useState(1);
  const [totalRounds, setTotalRounds] = useState(3);
  const [currentWord, setCurrentWord] = useState('');
  const [guessInput, setGuessInput] = useState('');
  const [chatMessages, setChatMessages] = useState([]);
  const [toasts, setToasts] = useState([]);
  const [usedWords, setUsedWords] = useState(new Set());
  const [correctGuessers, setCorrectGuessers] = useState([]);
  const [roundEnded, setRoundEnded] = useState(false);
  const [revealedLetters, setRevealedLetters] = useState({}); // {playerId: {0: 'B', 3: 'T', ...}}
  const [playerWords, setPlayerWords] = useState({}); // {playerId: 'WORD'}
  const [playerDrawings, setPlayerDrawings] = useState({}); // {playerId: [drawData]}
  const [currentGuessingPlayerIndex, setCurrentGuessingPlayerIndex] = useState(0);

  const gameSettings = location.state?.gameSettings;
  const roomCode = location.state?.roomCode;
  const [players, setPlayers] = useState(location.state?.players || []);
  const currentPlayerData = location.state?.currentPlayer;


  const currentPlayer = currentPlayerData || (players.length > 0 ? players[0] : null);
  const isCurrentPlayerDrawing = currentPlayer && players[currentDrawerIndex]?.id === currentPlayer.id;

  // Utility functions
  const getRandomWord = () => {
    const availableWords = WORDS.filter(word => !usedWords.has(word));
    if (availableWords.length === 0) {
      // Reset used words if all words are used
      setUsedWords(new Set());
      return WORDS[Math.floor(Math.random() * WORDS.length)];
    }
    const word = availableWords[Math.floor(Math.random() * availableWords.length)];
    setUsedWords(prev => new Set([...prev, word]));
    return word;
  };

  const showToast = (message, type = 'success') => {
    const id = Date.now();
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => {
      setToasts(prev => prev.filter(toast => toast.id !== id));
    }, 3000);
  };

  const updatePlayerScore = async (playerId, points) => {
    if (!roomCode) return;
    const playerRef = ref(db, `rooms/${roomCode}/players/${playerId}/score`);
    const currentScore = players.find(p => p.id === playerId)?.score || 0;
    await set(playerRef, currentScore + points);
  };

  const nextRound = async () => {
    if (!roomCode || !currentPlayer?.isHost) return;

    if (gamePhase === 'drawing') {
      // Drawing Phase: Move to next drawer
      const nextDrawerIndex = (currentDrawerIndex + 1) % players.length;

      // Save current player's drawing
      const drawingRef = ref(db, `rooms/${roomCode}/drawing`);
      const drawingSnapshot = await get(drawingRef);
      if (drawingSnapshot.exists()) {
        const currentDrawerId = players[currentDrawerIndex]?.id;
        const playerDrawingsRef = ref(db, `rooms/${roomCode}/playerDrawings/${currentDrawerId}`);
        await set(playerDrawingsRef, drawingSnapshot.val());
      }

      // Check if all players have drawn
      if (nextDrawerIndex === 0) {
        // All players have drawn, transition to guessing phase
        setGamePhase('guessing');
        setCurrentGuessingPlayerIndex(0);
        setRound(1);

        // Load first player's drawing
        const firstPlayerId = players[0]?.id;
        const firstPlayerDrawingRef = ref(db, `rooms/${roomCode}/playerDrawings/${firstPlayerId}`);
        const firstDrawingSnapshot = await get(firstPlayerDrawingRef);

        // Clear current drawing and load saved drawing
        const currentDrawingRef = ref(db, `rooms/${roomCode}/drawing`);
        await set(currentDrawingRef, firstDrawingSnapshot.val() || null);

        // Update Firebase
        const gameStateRef = ref(db, `rooms/${roomCode}/gameState`);
        await update(gameStateRef, {
          gamePhase: 'guessing',
          currentGuessingPlayerIndex: 0,
          currentRound: 1,
          timeLeft: 60,
          roundStartTime: Date.now(),
          correctGuessers: [],
          roundEnded: false,
          revealedLetters: {}
        });

        setTimeLeft(60);
        setCorrectGuessers([]);
        setRoundEnded(false);
        setRevealedLetters({});
      } else {
        // Continue drawing phase with next player
        const newWord = getRandomWord();
        setCurrentWord(newWord);

        // Update Firebase
        const gameStateRef = ref(db, `rooms/${roomCode}/gameState`);
        await update(gameStateRef, {
          currentDrawerIndex: nextDrawerIndex,
          currentWord: newWord,
          timeLeft: 30,
          roundStartTime: Date.now()
        });

        // Clear canvas for next drawer
        const canvas = document.querySelector('canvas');
        if (canvas) {
          const ctx = canvas.getContext('2d');
          ctx.fillStyle = '#FFFFFF';
          ctx.fillRect(0, 0, canvas.width, canvas.height);
        }

        // Clear drawing in Firebase
        const drawingRef = ref(db, `rooms/${roomCode}/drawing`);
        await set(drawingRef, null);

        setCurrentDrawerIndex(nextDrawerIndex);
        setTimeLeft(30);
      }
    } else {
      // Guessing Phase: Move to next player's drawing or next round
      const nextGuessingIndex = (currentGuessingPlayerIndex + 1) % players.length;
      const nextRoundNum = nextGuessingIndex === 0 ? round + 1 : round;

      // Check if game is over
      if (nextRoundNum > totalRounds) {
        const gameStateRef = ref(db, `rooms/${roomCode}/gameState`);
        await update(gameStateRef, { gameOver: true });
        return;
      }

      // Load next player's drawing
      const nextPlayerId = players[nextGuessingIndex]?.id;
      const nextPlayerDrawingRef = ref(db, `rooms/${roomCode}/playerDrawings/${nextPlayerId}`);
      const nextDrawingSnapshot = await get(nextPlayerDrawingRef);

      // Clear canvas and load saved drawing
      const canvas = document.querySelector('canvas');
      if (canvas) {
        const ctx = canvas.getContext('2d');
        ctx.fillStyle = '#FFFFFF';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        // Redraw from saved data
        if (nextDrawingSnapshot.exists()) {
          const drawingData = nextDrawingSnapshot.val();
          Object.values(drawingData).forEach(drawData => {
            drawOnCanvas(drawData);
          });
        }
      }

      // Update current drawing in Firebase
      const currentDrawingRef = ref(db, `rooms/${roomCode}/drawing`);
      await set(currentDrawingRef, nextDrawingSnapshot.val() || null);

      // Reset for next guessing round
      setCorrectGuessers([]);
      setRoundEnded(false);
      setCurrentGuessingPlayerIndex(nextGuessingIndex);
      setRound(nextRoundNum);

      // Update Firebase
      const gameStateRef = ref(db, `rooms/${roomCode}/gameState`);
      await update(gameStateRef, {
        currentGuessingPlayerIndex: nextGuessingIndex,
        currentRound: nextRoundNum,
        timeLeft: 60,
        roundStartTime: Date.now(),
        correctGuessers: [],
        roundEnded: false
      });

      setTimeLeft(60);
    }
  };

  useEffect(() => {
    if (gameSettings?.rounds) {
      setTotalRounds(parseInt(gameSettings.rounds));
    }

    // Initialize game state in Firebase (only host does this)
    if (roomCode && currentPlayer?.isHost) {
      const checkAndInitialize = async () => {
        const gameStateRef = ref(db, `rooms/${roomCode}/gameState`);
        const snapshot = await get(gameStateRef);

        // Only initialize if game state doesn't exist or game is being restarted
        if (!snapshot.exists() || snapshot.val()?.gameOver) {
          // Assign a word to each player
          const wordsForPlayers = {};
          players.forEach(player => {
            wordsForPlayers[player.id] = getRandomWord();
          });

          // Set first player's word
          const firstWord = wordsForPlayers[players[0]?.id];
          setCurrentWord(firstWord);
          setPlayerWords(wordsForPlayers);

          await set(gameStateRef, {
            gamePhase: 'drawing',
            currentRound: 1,
            currentDrawerIndex: 0,
            currentGuessingPlayerIndex: 0,
            timeLeft: 30,
            currentWord: firstWord,
            playerWords: wordsForPlayers,
            roundStartTime: Date.now(),
            correctGuessers: [],
            roundEnded: false,
            gameOver: false,
            revealedLetters: {}
          });
        }
      };
      checkAndInitialize();
    }
  }, [gameSettings, roomCode, currentPlayer]);

  useEffect(() => {
    if (timeLeft > 0 && gameState === 'playing' && !roundEnded) {
      const timer = setTimeout(() => setTimeLeft(timeLeft - 1), 1000);
      return () => clearTimeout(timer);
    } else if (timeLeft === 0 && currentPlayer?.isHost) {
      // Round ended - no points awarded if no one guessed correctly
      if (correctGuessers.length === 0) {
        showToast('Time up! No one guessed correctly. No points awarded.', 'info');
      }
      // Move to next round
      setTimeout(() => nextRound(), 2000);
    }
  }, [timeLeft, gameState, currentPlayer, correctGuessers.length, roundEnded, players, currentDrawerIndex]);

  // Firebase listeners
  useEffect(() => {
    if (!roomCode) return;

    // Listen to players
    const playersRef = ref(db, `rooms/${roomCode}/players`);
    const unsubscribePlayers = onValue(playersRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const playersList = Object.values(data).map(p => ({
          ...p,
          score: p.score || 0
        }));
        setPlayers(playersList);
      }
    });

    // Listen to drawing
    const drawingRef = ref(db, `rooms/${roomCode}/drawing`);
    const unsubscribeDrawing = onValue(drawingRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        // Redraw from Firebase unless actively drawing in drawing phase
        if (!(isCurrentPlayerDrawing && gamePhase === 'drawing')) {
          const canvas = document.querySelector('canvas');
          if (canvas) {
            const ctx = canvas.getContext('2d');
            ctx.fillStyle = '#FFFFFF';
            ctx.fillRect(0, 0, canvas.width, canvas.height);
            Object.values(data).forEach(drawData => {
              drawOnCanvas(drawData);
            });
          }
        }
        // Drawing players in drawing phase handle their own drawing locally, but respond to clear commands
        else if (isCurrentPlayerDrawing && gamePhase === 'drawing') {
          // Check if there's a clear command from another source
          const clearCommands = Object.values(data).filter(drawData => drawData.type === 'clear');
          if (clearCommands.length > 0) {
            const canvas = document.querySelector('canvas');
            if (canvas) {
              const ctx = canvas.getContext('2d');
              ctx.fillStyle = '#FFFFFF';
              ctx.fillRect(0, 0, canvas.width, canvas.height);
            }
          }
        }
        // For drawing players, we don't need to redraw from Firebase since they draw locally
      }
    });

    // Listen to game state
    const gameStateRef = ref(db, `rooms/${roomCode}/gameState`);
    const unsubscribeGameState = onValue(gameStateRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        setGamePhase(data.gamePhase || 'drawing');
        setRound(data.currentRound || 1);
        setCurrentDrawerIndex(data.currentDrawerIndex || 0);
        setCurrentGuessingPlayerIndex(data.currentGuessingPlayerIndex || 0);
        setTimeLeft(data.timeLeft || 30);
        setCurrentWord(data.currentWord || '');
        setCorrectGuessers(data.correctGuessers || []);
        setRevealedLetters(data.revealedLetters || {});
        if (data.playerWords) {
          setPlayerWords(data.playerWords);
        }
        if (data.gameOver) {
          // Game over - navigate all players using current synchronized players state
          navigate('/gameover', {
            state: { 
              players: players.map(p => ({ ...p, score: p.score || 0 })),
              roomCode,
              gameSettings,
              currentPlayer
            }
          });
        }
        if (data.roundEnded) {
          setRoundEnded(true);
          if (currentPlayer?.isHost && !roundEnded) {
            nextRound();
          }
        } else {
          setRoundEnded(false);
        }
      }
    });

    // Listen to chat
    const chatRef = ref(db, `rooms/${roomCode}/chat`);
    const unsubscribeChat = onValue(chatRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const messages = Object.values(data).sort((a, b) => a.timestamp - b.timestamp);
        setChatMessages(messages);
      }
    });

    return () => {
      unsubscribePlayers();
      unsubscribeDrawing();
      unsubscribeGameState();
      unsubscribeChat();
    };
  }, [roomCode, isCurrentPlayerDrawing]);

  const sendDrawing = (drawData) => {
    if (!roomCode) return;
    const drawingRef = ref(db, `rooms/${roomCode}/drawing`);
    push(drawingRef, {
      ...drawData,
      player: currentPlayer?.name,
      timestamp: serverTimestamp()
    });
  };

  const sendGuess = async () => {
    if (!guessInput.trim() || !roomCode || !currentPlayer) return;

    const guess = guessInput.trim().toUpperCase();

    // Get the correct word based on game phase
    let correctWord = currentWord;
    if (gamePhase === 'guessing') {
      const guessingPlayerId = players[currentGuessingPlayerIndex]?.id;
      correctWord = playerWords[guessingPlayerId] || currentWord;
    }

    const isCorrect = guess === correctWord;

    // Check if player already guessed correctly
    if (isCorrect && correctGuessers.includes(currentPlayer.id)) {
      showToast('You already guessed correctly!', 'warning');
      setGuessInput('');
      return;
    }

    const chatRef = ref(db, `rooms/${roomCode}/chat`);
    await push(chatRef, {
      player: currentPlayer.name,
      message: guessInput.trim(),
      time: new Date().toLocaleTimeString(),
      type: isCorrect ? 'correct' : 'guess',
      timestamp: serverTimestamp()
    });

    if (isCorrect) {
      // Award points to guesser
      await updatePlayerScore(currentPlayer.id, 10);
      showToast(`${currentPlayer.name} guessed correctly! +10 points`, 'success');

      // Add to correct guessers
      const newCorrectGuessers = [...correctGuessers, currentPlayer.id];
      setCorrectGuessers(newCorrectGuessers);

      // Update Firebase
      const gameStateRef = ref(db, `rooms/${roomCode}/gameState`);
      await update(gameStateRef, { correctGuessers: newCorrectGuessers, roundEnded: true });

      // End round immediately when any player guesses correctly
      setRoundEnded(true);
    } else if (gamePhase === 'guessing') {
      // Check for correct letter positions in guessing phase
      const newRevealedLetters = { ...revealedLetters };
      const guessingPlayerId = players[currentGuessingPlayerIndex]?.id;

      if (!newRevealedLetters[currentPlayer.id]) {
        newRevealedLetters[currentPlayer.id] = {};
      }

      let hasNewReveals = false;
      for (let i = 0; i < Math.min(guess.length, correctWord.length); i++) {
        if (guess[i] === correctWord[i] && !newRevealedLetters[currentPlayer.id][i]) {
          newRevealedLetters[currentPlayer.id][i] = correctWord[i];
          hasNewReveals = true;
        }
      }

      if (hasNewReveals) {
        setRevealedLetters(newRevealedLetters);

        // Update Firebase
        const gameStateRef = ref(db, `rooms/${roomCode}/gameState`);
        await update(gameStateRef, { revealedLetters: newRevealedLetters });

        showToast('Correct letter position revealed!', 'info');
      }
    }

    setGuessInput('');
  };

  const drawOnCanvas = (data) => {
    const canvas = document.querySelector('canvas');
    if (canvas) {
      const ctx = canvas.getContext('2d');
      ctx.strokeStyle = data.color;
      ctx.lineWidth = data.size;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';

      if (data.type === 'start') {
        ctx.beginPath();
        ctx.moveTo(data.x, data.y);
      } else if (data.type === 'draw') {
        ctx.lineTo(data.x, data.y);
        ctx.stroke();
      } else if (data.type === 'clear') {
        ctx.fillStyle = '#FFFFFF';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      }
    }
  };

  return (
    <div className={styles.gameContainer}>
      <div className={styles.gameWrapper}>
        <GameHeader
          round={round}
          totalRounds={totalRounds}
          playersLength={players.length}
          timeLeft={timeLeft}
          gameState={gameState}
          gamePhase={gamePhase}
        />

        {/* Answer Input for Non-Drawing Players OR Live Guesses for Drawing Players */}
        {gamePhase === 'drawing' && !isCurrentPlayerDrawing ? (
          <div className={styles.answerSection}>
            <div className={styles.answerContainer}>
              <h3 className={styles.answerTitle}>Watch {players[currentDrawerIndex]?.name} draw their word</h3>
              <p style={{ textAlign: 'center', color: '#666', marginTop: '1rem' }}>
                Drawing phase - Guessing will begin after all players draw
              </p>
            </div>
          </div>
        ) : gamePhase === 'guessing' && currentPlayer.id !== players[currentGuessingPlayerIndex]?.id ? (
          <div className={styles.answerSection}>
            <div className={styles.answerContainer}>
              <h3 className={styles.answerTitle}>What's being drawn?</h3>
              <div className={styles.answerInputContainer}>
                <input
                  type="text"
                  value={guessInput}
                  onChange={(e) => setGuessInput(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && sendGuess()}
                  placeholder="Type your guess here..."
                  className={styles.answerInput}
                  autoFocus
                />
                <button onClick={sendGuess} className={styles.answerButton}>
                  <Send size={20} />
                  Guess
                </button>
              </div>
            </div>
          </div>
        ) : isCurrentPlayerDrawing && gamePhase === 'drawing' ? (
          <div className={styles.answerSection}>
            <div className={styles.answerContainer}>
              <h3 className={styles.answerTitle}>Draw your word</h3>
              <p style={{ textAlign: 'center', color: '#666', marginTop: '1rem' }}>
                Use the tools below to draw your word
              </p>
            </div>
          </div>
        ) : gamePhase === 'guessing' && currentPlayer.id === players[currentGuessingPlayerIndex]?.id ? (
          <div className={styles.answerSection}>
            <div className={styles.answerContainer}>
              <h3 className={styles.answerTitle}>Your drawing is being guessed</h3>
              <p style={{ textAlign: 'center', color: '#666', marginTop: '1rem' }}>
                Watch as others try to guess your word
              </p>
            </div>
          </div>
        ) : null}

        <div className={styles.gameGrid}>
          <div>
            <PlayerList 
              players={players} 
              currentDrawerIndex={currentDrawerIndex}
              currentGuessingPlayerIndex={currentGuessingPlayerIndex}
              gamePhase={gamePhase}
            />
          </div>

          <div>
            <GameCanvas
              currentWord={currentWord}
              gamePhase={gamePhase}
              currentDrawerName={players[currentDrawerIndex]?.name || 'Unknown'}
              currentGuessingPlayerName={players[currentGuessingPlayerIndex]?.name || 'Unknown'}
              isCurrentPlayerDrawing={isCurrentPlayerDrawing}
              onSendDrawing={sendDrawing}
              playerWords={playerWords}
              currentGuessingPlayerIndex={currentGuessingPlayerIndex}
              players={players}
              revealedLetters={revealedLetters}
              currentPlayerId={currentPlayer?.id}
            />
          </div>

          <div>
            <ChatPanel
              messages={chatMessages}
              isCurrentPlayerDrawing={isCurrentPlayerDrawing}
              gamePhase={gamePhase}
              guessInput={guessInput}
              setGuessInput={setGuessInput}
              sendGuess={sendGuess}
              currentWord={currentWord}
              isCurrentPlayerGuessing={currentPlayer?.id === players[currentGuessingPlayerIndex]?.id}
            />
          </div>
        </div>
      </div>

      {/* Toast Notifications */}
      <div className={styles.toastContainer}>
        {toasts.map(toast => (
          <Toast key={toast.id} message={toast.message} type={toast.type} />
        ))}
      </div>
    </div>
  );
};

const GameHeader = ({ round, totalRounds, playersLength, timeLeft, gamePhase }) => {
  const getPhaseText = () => {
    if (gamePhase === 'drawing') {
      return 'Drawing Phase - All players drawing';
    }
    return `Guessing Phase - Round ${round} of ${totalRounds}`;
  };

  return (
    <div className={styles.header}>
      <div className={styles.headerContent}>
        <div className={styles.headerLeft}>
          <div className={styles.headerIcon}>
            <Trophy />
          </div>
          <div>
            <h1 className={styles.headerTitle}>Draw & Guess</h1>
            <p className={styles.headerSubtitle}>{getPhaseText()}</p>
          </div>
        </div>

        <div className={styles.headerRight}>
          <div className={styles.timerBox}>
            <Clock />
            <span className={`${styles.timerText} ${timeLeft <= 10 ? styles.timerWarning : ''}`}>
              {timeLeft}s
            </span>
          </div>
        </div>
      </div>
    </div>
  );
};

const PlayerList = ({ players, currentDrawerIndex, currentGuessingPlayerIndex, gamePhase }) => {
  const getPlayerLabel = (index) => {
    if (gamePhase === 'drawing' && index === currentDrawerIndex) {
      return ' ✏️ Drawing';
    }
    if (gamePhase === 'guessing' && index === currentGuessingPlayerIndex) {
      return ' 🎨 Their turn';
    }
    return '';
  };

  const isActivePlayer = (index) => {
    if (gamePhase === 'drawing') {
      return index === currentDrawerIndex;
    }
    return index === currentGuessingPlayerIndex;
  };

  return (
    <div className={styles.playerPanel}>
      <div className={styles.playerHeader}>
        <Users />
        <h2 className={styles.playerTitle}>Players</h2>
      </div>

      <div className={styles.playerList}>
        {players.map((player, index) => (
          <div
            key={player.id}
            className={`${styles.playerItem} ${
              isActivePlayer(index) ? styles.playerItemActive : styles.playerItemInactive
            }`}
          >
            <div className={styles.playerInfo}>
              <span className={styles.playerAvatar}>{player.avatar}</span>
              <div>
                <p className={`${styles.playerName} ${isActivePlayer(index) ? styles.playerNameActive : ''}`}>
                  {player.name}
                  {getPlayerLabel(index)}
                </p>
                <p className={styles.playerScore}>{player.score || 0} points</p>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

const GameCanvas = ({ 
  currentWord, 
  gamePhase,
  currentDrawerName, 
  currentGuessingPlayerName,
  isCurrentPlayerDrawing, 
  onSendDrawing,
  playerWords,
  currentGuessingPlayerIndex,
  players,
  revealedLetters,
  currentPlayerId
}) => {
  const canvasRef = useRef(null);
  const [brushSize, setBrushSize] = useState(5);
  const [brushColor, setBrushColor] = useState('#000000');
  const [tool, setTool] = useState('brush');
  const [isDrawing, setIsDrawing] = useState(false);

  const colors = ['#000000', '#FF0000', '#00FF00', '#0000FF', '#FFFF00', '#FF00FF', '#00FFFF', '#FFA500'];

  // Generate word hint with underscores for guessers, showing revealed letters
  const getWordHint = (word, playerId) => {
    if (!word) return '_ _ _ _ _';
    const playerRevealed = revealedLetters[playerId] || {};
    return word.split('').map((char, index) => {
      if (playerRevealed[index]) {
        return playerRevealed[index];
      }
      return '_';
    }).join(' ');
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
    }
  }, []);

  // Clear canvas when round changes
  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
    }
  }, [currentWord]); // Clear when word changes (new round)

  const startDrawing = (e) => {
    if (!isCurrentPlayerDrawing || gamePhase !== 'drawing') return;
    setIsDrawing(true);
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    // Draw locally for immediate feedback
    const ctx = canvas.getContext('2d');
    ctx.strokeStyle = tool === 'eraser' ? '#FFFFFF' : brushColor;
    ctx.lineWidth = brushSize;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.beginPath();
    ctx.moveTo(x, y);

    onSendDrawing({
      type: 'start',
      x, y,
      color: tool === 'eraser' ? '#FFFFFF' : brushColor,
      size: brushSize
    });
  };

  const draw = (e) => {
    if (!isDrawing || !isCurrentPlayerDrawing || gamePhase !== 'drawing') return;
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    // Draw locally for immediate feedback
    const ctx = canvas.getContext('2d');
    ctx.lineTo(x, y);
    ctx.stroke();

    onSendDrawing({
      type: 'draw',
      x, y,
      color: tool === 'eraser' ? '#FFFFFF' : brushColor,
      size: brushSize
    });
  };

  const stopDrawing = () => {
    setIsDrawing(false);
  };

  const clearCanvas = () => {
    if (!isCurrentPlayerDrawing || gamePhase !== 'drawing') return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    ctx.fillStyle = '#FFFFFF';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    onSendDrawing({ type: 'clear' });
  };

  return (
    <div className={styles.canvasPanel}>
      <div className={styles.wordDisplay}>
        <div className={styles.wordBox}>
          <h3 className={styles.wordTitle}>
            {gamePhase === 'drawing' && isCurrentPlayerDrawing ? (
              `Draw: ${currentWord}`
            ) : gamePhase === 'drawing' && !isCurrentPlayerDrawing ? (
              <div>{currentDrawerName} is drawing their word...</div>
            ) : gamePhase === 'guessing' && !isCurrentPlayerDrawing ? (
              <>
                <div>Guess {currentGuessingPlayerName}'s drawing</div>
                <div style={{ fontSize: '1.5rem', marginTop: '0.5rem', letterSpacing: '0.3rem' }}>
                  {getWordHint(playerWords[players[currentGuessingPlayerIndex]?.id], currentPlayerId)}
                </div>
              </>
            ) : (
              <div>Guessing phase - Watch others guess!</div>
            )}
          </h3>
        </div>
      </div>

      {isCurrentPlayerDrawing && gamePhase === 'drawing' && (
        <div className={styles.toolsContainer}>
          <div className={styles.colorPalette}>
            {colors.map((color) => (
              <button
                key={color}
                onClick={() => setBrushColor(color)}
                className={`${styles.colorButton} ${brushColor === color ? styles.colorButtonActive : ''}`}
                style={{ backgroundColor: color }}
              />
            ))}
          </div>

          <div className={styles.toolButtons}>
            <button
              onClick={() => setTool('brush')}
              className={`${styles.toolButton} ${tool === 'brush' ? styles.toolButtonActive : ''}`}
            >
              <Palette />
            </button>
            <button
              onClick={() => setTool('eraser')}
              className={`${styles.toolButton} ${tool === 'eraser' ? styles.toolButtonActive : ''}`}
            >
              <Eraser />
            </button>
            <button onClick={clearCanvas} className={styles.toolButton}>
              <RotateCcw />
            </button>
          </div>

          <div className={styles.brushSizeContainer}>
            <span className={styles.brushSizeLabel}>Size:</span>
            <input
              type="range"
              min="1"
              max="20"
              value={brushSize}
              onChange={(e) => setBrushSize(e.target.value)}
              className={styles.brushSizeSlider}
            />
            <span className={styles.brushSizeLabel}>{brushSize}px</span>
          </div>
        </div>
      )}

      <div className={styles.canvasContainer}>
        <canvas
          ref={canvasRef}
          width={600}
          height={400}
          className={styles.canvas}
          onMouseDown={startDrawing}
          onMouseMove={draw}
          onMouseUp={stopDrawing}
          onMouseLeave={stopDrawing}
        />
      </div>
    </div>
  );
};

const ChatPanel = ({ messages, isCurrentPlayerDrawing, gamePhase, guessInput, setGuessInput, sendGuess, currentWord, isCurrentPlayerGuessing }) => {
  return (
    <div className={styles.chatPanel}>
      <div className={styles.chatHeader}>
        <h3 className={styles.chatTitle}>Guesses</h3>
      </div>

      <div className={styles.chatMessages}>
        {messages.map((msg) => (
          <div key={msg.id} className={styles.messageContainer}>
            <div className={styles.messageHeader}>
              <span className={styles.messageSender}>{msg.player}</span>
              <span className={styles.messageTime}>{msg.time}</span>
            </div>
            <div className={`${styles.messageContent} ${msg.type === 'correct' ? styles.correctGuess : ''}`}>
              {msg.message}
            </div>
          </div>
        ))}
      </div>

      {/* Guess Input for Non-Drawing Players during Drawing Phase */}
      {(gamePhase === 'drawing' && !isCurrentPlayerDrawing) || (gamePhase === 'guessing' && !isCurrentPlayerGuessing) ? (
        <div className={styles.guessInputContainer}>
          <input
            type="text"
            value={guessInput}
            onChange={(e) => setGuessInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && sendGuess()}
            placeholder="Guess the word..."
            className={styles.guessInput}
            autoFocus
          />
          <button onClick={sendGuess} className={styles.guessButton}>
            <Send size={18} />
          </button>
        </div>
      ) : isCurrentPlayerDrawing ? (
        <div className={styles.drawerMessage}>
          <p>You are drawing! Other players are guessing...</p>
        </div>
      ) : null}
    </div>
  );
};

const Toast = ({ message, type }) => {
  const getIcon = () => {
    switch (type) {
      case 'success':
        return <CheckCircle size={20} />;
      case 'warning':
        return <XCircle size={20} />;
      case 'info':
        return <Trophy size={20} />;
      default:
        return <CheckCircle size={20} />;
    }
  };

  return (
    <div className={`${styles.toast} ${styles[`toast${type.charAt(0).toUpperCase() + type.slice(1)}`]}`}>
      {getIcon()}
      <span>{message}</span>
    </div>
  );
};

export default DrawingGame;
